import{_ as a}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as l}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as i,o,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"hi/Safety/cloudflare-api-token.md","filePath":"hi/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"hi/Safety/cloudflare-api-token.md"};function n(c,e,s,p,u,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Cloudflare API credentials से ImgBed files बदलने के बाद Cloudflare CDN cache purge कर सकता है।</p><p><img src="'+a+'" alt="Cloudflare API Token settings" loading="lazy"></p><h2 id="कहाँ-सेट-करें" tabindex="-1">कहाँ सेट करें <a class="header-anchor" href="#कहाँ-सेट-करें" aria-label="Permalink to &quot;कहाँ सेट करें&quot;">​</a></h2><p>Admin panel खोलें, फिर यहाँ जाएँ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>आपको ये fields भरने होंगे:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="यह-setting-क्या-करती-है" tabindex="-1">यह Setting क्या करती है <a class="header-anchor" href="#यह-setting-क्या-करती-है" aria-label="Permalink to &quot;यह Setting क्या करती है&quot;">​</a></h2><p>Cloudflare public image URLs को cache कर सकता है।</p><p>Cache की वजह से images तेज़ खुलती हैं, लेकिन file delete, block, replace या move करने के बाद भी पुराना content कुछ समय तक दिख सकता है।</p><p>Cloudflare API credentials configure होने के बाद ImgBed उन operations के पूरा होते ही related Cloudflare cache purge करने की कोशिश करता है।</p><p>यह इन स्थितियों में उपयोगी है:</p><ul><li>आपने image delete की है और चाहते हैं कि public link जल्द से जल्द काम करना बंद कर दे।</li><li>आपने image block की है और चाहते हैं कि visitors original file न देखें।</li><li>आपने same name से file replace की है और चाहते हैं कि visitors जल्दी नया version देखें।</li><li>आपने files move या rename की हैं और चाहते हैं कि पुराने path का cache जल्दी refresh हो।</li><li>आपने public access rules बदले हैं और चाहते हैं कि public gallery या random image cache जल्दी update हो।</li></ul><h2 id="खाली-छोड़ने-पर-क्या-होगा" tabindex="-1">खाली छोड़ने पर क्या होगा <a class="header-anchor" href="#खाली-छोड़ने-पर-क्या-होगा" aria-label="Permalink to &quot;खाली छोड़ने पर क्या होगा&quot;">​</a></h2><p>इस setting के बिना भी ImgBed सामान्य रूप से काम करता रहेगा।</p><p>फर्क सिर्फ इतना है कि ImgBed Cloudflare CDN cache को actively purge नहीं करेगा। Visitors को पुराना content तब तक दिख सकता है जब तक Cloudflare cache अपने आप expire न हो जाए।</p><h2 id="zone-id-कैसे-खोजें" tabindex="-1">Zone ID कैसे खोजें <a class="header-anchor" href="#zone-id-कैसे-खोजें" aria-label="Permalink to &quot;Zone ID कैसे खोजें&quot;">​</a></h2><p>Zone ID उस site का Cloudflare Zone ID है जिसका इस्तेमाल आपके ImgBed domain में हो रहा है।</p><ol><li>Cloudflare dashboard में sign in करें।</li><li>वह site खोलें जिसमें आपका ImgBed domain है।</li><li>Site overview page पर <code>Zone ID</code> ढूँढें।</li><li>उसे ImgBed के <code>Zone ID</code> field में copy करें।</li></ol><p>यह site Zone ID है, account ID नहीं।</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>वही email address डालें जिससे आप Cloudflare में sign in करते हैं।</p><p>यह नीचे दिए गए API Key से match करना चाहिए।</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>अपना Cloudflare Global API Key डालें।</p><ol><li>Cloudflare dashboard में sign in करें।</li><li>अपना profile खोलें।</li><li>API Tokens page पर जाएँ।</li><li><code>Global API Key</code> ढूँढें।</li><li>उसे view करके copy करें।</li><li>ImgBed के <code>API Key</code> field में paste करें।</li></ol><p><img src="'+l+'" alt="View global API key" loading="lazy"></p><h2 id="कब-लागू-होता-है" tabindex="-1">कब लागू होता है <a class="header-anchor" href="#कब-लागू-होता-है" aria-label="Permalink to &quot;कब लागू होता है&quot;">​</a></h2><p>Fields भरने के बाद settings save करें।</p><p>इसके बाद future file changes पर ImgBed automatically Cloudflare cache purge करने की कोशिश करेगा। पुराने operations retroactively purge नहीं होते। अगर आपने setup से पहले कोई file delete या replace की है, तो Cloudflare cache expire होने का इंतज़ार करें या Cloudflare में manually purge करें।</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="क्या-यह-ज़रूरी-है" tabindex="-1">क्या यह ज़रूरी है? <a class="header-anchor" href="#क्या-यह-ज़रूरी-है" aria-label="Permalink to &quot;क्या यह ज़रूरी है?&quot;">​</a></h3><p>नहीं।</p><p>अगर आपका domain Cloudflare इस्तेमाल नहीं करता, या CDN cache delay से आपको दिक्कत नहीं है, तो इसे खाली छोड़ सकते हैं।</p><h3 id="क्या-गलत-credentials-uploads-तोड़-देंगे" tabindex="-1">क्या गलत Credentials uploads तोड़ देंगे? <a class="header-anchor" href="#क्या-गलत-credentials-uploads-तोड़-देंगे" aria-label="Permalink to &quot;क्या गलत Credentials uploads तोड़ देंगे?&quot;">​</a></h3><p>आम तौर पर नहीं।</p><p>गलत credentials केवल ImgBed को Cloudflare cache purge करने से रोकेंगे। Upload और normal file access चलते रहने चाहिए।</p><h3 id="deleted-image-फिर-भी-क्यों-खुल-रही-है" tabindex="-1">Deleted Image फिर भी क्यों खुल रही है? <a class="header-anchor" href="#deleted-image-फिर-भी-क्यों-खुल-रही-है" aria-label="Permalink to &quot;Deleted Image फिर भी क्यों खुल रही है?&quot;">​</a></h3><p>सबसे आम वजह है कि Cloudflare के पास अभी भी पुरानी file cached है।</p><p>सही Cloudflare API credentials होने पर ImgBed file delete करते समय related URL cache purge करता है।</p><h3 id="file-replace-करने-के-बाद-भी-पुरानी-image-क्यों-दिख-रही-है" tabindex="-1">File replace करने के बाद भी पुरानी Image क्यों दिख रही है? <a class="header-anchor" href="#file-replace-करने-के-बाद-भी-पुरानी-image-क्यों-दिख-रही-है" aria-label="Permalink to &quot;File replace करने के बाद भी पुरानी Image क्यों दिख रही है?&quot;">​</a></h3><p>यह भी आम तौर पर CDN cache की वजह से होता है।</p><p>यह setting configure होने के बाद, same name वाली file overwrite होने पर ImgBed पुराने URL cache को purge करने की कोशिश करता है।</p>',44)])])}const b=i(d,[["render",n]]);export{I as __pageData,b as default};
